public static ETGNewInjectionofCylindersController construct()
{
    return new ETGNewInjectionofCylindersController();

}

/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    ETGNewInjectionofCylindersController controller =  ETGNewInjectionofCylindersController::construct();

    controller.parmReportName(ssrsReportStr(ETGNewInjectionofCylindersReport, Report));
    controller.parmArgs(_args);
    controller.parmLoadFromSysLastValue(false);
    controller.startOperation();
}
